package com.socialblog.interaction.application;import com.fasterxml.jackson.core.JsonProcessingException;import com.fasterxml.jackson.databind.ObjectMapper;import com.socialblog.interaction.domain.*;import com.socialblog.interaction.web.CorrelationIdProvider;import org.springframework.stereotype.Component;import java.time.Instant;import java.util.*;@Component public class DomainEventFactory{private final ObjectMapper json;private final CorrelationIdProvider ids;public DomainEventFactory(ObjectMapper j,CorrelationIdProvider i){json=j;ids=i;}public OutboxEvent created(Interaction x,UUID recipient){return event("InteractionCreated",x,recipient);}public OutboxEvent removed(Interaction x){return event("InteractionRemoved",x,null);}private OutboxEvent event(String type,Interaction x,UUID recipient){UUID id=UUID.randomUUID();Instant now=Instant.now();Map<String,Object>payload=new LinkedHashMap<>();payload.put("interactionId",x.getId());payload.put("actorId",x.getActorId());payload.put("targetType",x.getTargetType());payload.put("targetId",x.getTargetId());payload.put("recipientId",recipient);Map<String,Object>e=new LinkedHashMap<>();e.put("eventId",id);e.put("eventType",type);e.put("eventVersion",1);e.put("occurredAt",now);e.put("correlationId",ids.current());e.put("actorId",x.getActorId());e.put("payload",payload);try{return new OutboxEvent(id,x.getId(),type,json.writeValueAsString(e),now);}catch(JsonProcessingException z){throw new IllegalStateException(z);}}}
